CREATE OR REPLACE FUNCTION public.log_task_completion() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $func$ BEGIN IF (OLD.completed_at IS NULL AND NEW.completed_at IS NOT NULL) THEN INSERT INTO public.activity_log (user_id, entity_type, entity_id, action, payload) VALUES (NEW.user_id, 'task', NEW.id, 'completed', jsonb_build_object('title', NEW.title, 'project_id', NEW.project_id, 'priority', NEW.priority)); END IF; RETURN NEW; END; $func$; DROP TRIGGER IF EXISTS log_task_completion_trigger ON public.tasks; CREATE TRIGGER log_task_completion_trigger AFTER UPDATE OF completed_at ON public.tasks FOR EACH ROW EXECUTE FUNCTION public.log_task_completion();